def md_inline(text: str) -> str:
    text = re.sub(r"\*\*(.+?)\*\*", r"<strong>\1</strong>", text)
    text = re.sub(r"`([^`]+)`", r"<code>\1</code>", text)
    text = re.sub(
        r"\[([^\]]+)\]\(([^)]+)\)",
        r'<a href="\2">\1</a>',
        text,
    )
    return text


def table_to_html(rows: list[str]) -> str:
    html = ['<table class="tbl">']
    for i, row in enumerate(rows):
        cells = [c.strip() for c in row.strip().strip("|").split("|")]
        if all(set(c.replace(":", "").replace("-", "").replace(" ", "")) == set() or c.replace("-", "").replace(":", "").replace(" ", "") == "" for c in cells):
            # separator row like |---|---|
            continue
        tag = "th" if i == 0 else "td"
        html.append("<tr>" + "".join(f"<{tag}>{md_inline(c)}</{tag}>" for c in cells) + "</tr>")
    html.append("</table>")
    return "\n".join(html)


def md_to_html(md: str) -> str:
    lines = md.splitlines()
    out: list[str] = []
    i = 0
    in_ul = False
    in_ol = False

    def close_lists():
        nonlocal in_ul, in_ol
        if in_ul:
            out.append("</ul>")
            in_ul = False
        if in_ol:
            out.append("</ol>")
            in_ol = False

    while i < len(lines):
        line = lines[i]
        stripped = line.strip()

        # tables
        if stripped.startswith("|") and i + 1 < len(lines) and lines[i + 1].strip().startswith("|"):
            close_lists()
            rows = []
            while i < len(lines) and lines[i].strip().startswith("|"):
                rows.append(lines[i])
                i += 1
            out.append(table_to_html(rows))
            continue

        if stripped == "---":
            close_lists()
            out.append('<hr class="sep">')
            i += 1
            continue

        if stripped.startswith("# "):
            close_lists()
            out.append(f'<h1>{md_inline(stripped[2:])}</h1>')
            i += 1
            continue
        if stripped.startswith("## "):
            close_lists()
            out.append(f'<h2 class="section-title">{md_inline(stripped[3:])}</h2>')
            i += 1
            continue
        if stripped.startswith("### "):
            close_lists()
            out.append(f"<h3>{md_inline(stripped[4:])}</h3>")
            i += 1
            continue

        # question header
        if stripped.startswith("**سؤال"):
            close_lists()
            out.append(f'<div class="q-head">{md_inline(stripped)}</div>')
            i += 1
            continue

        # answer / explain / source lines
        if stripped.startswith("**پاسخ صحیح:**") or stripped.startswith("**توضیح:**") or stripped.startswith("**منبع:**"):
            close_lists()
            cls = "answer" if "پاسخ" in stripped else ("explain" if "توضیح" in stripped else "source")
            out.append(f'<p class="{cls}">{md_inline(stripped)}</p>')
            i += 1
            continue

        # numbered options 1) 2) 3) 4) or ۱) etc
        if re.match(r"^[1-4۱-۴]\)\s+", stripped):
            if not in_ol:
                close_lists()
                out.append('<ol class="options" start="1">')
                in_ol = True
            item = re.sub(r"^[1-4۱-۴]\)\s+", "", stripped)
            out.append(f"<li>{md_inline(item)}</li>")
            i += 1
            continue

        # bullet lists
        if stripped.startswith("- "):
            if not in_ul:
                close_lists()
                out.append("<ul>")
                in_ul = True
            out.append(f"<li>{md_inline(stripped[2:])}</li>")
            i += 1
            continue

        if stripped == "":
            close_lists()
            i += 1
            continue

        close_lists()
        # page break marker before بخش titles already handled via h1/h2
        out.append(f"<p>{md_inline(stripped)}</p>")
        i += 1

    close_lists()
    return "\n".join(out)


