def build_merged_md(files: list[Path]) -> str:
    parts = []
    for p in files:
        text = p.read_text(encoding="utf-8")
        # drop relative link-only usefulness for PDF; keep text
        parts.append(text.strip())
        parts.append("\n\n---\n\n")
    return "\n".join(parts).rstrip() + "\n"


def main() -> None:
    files = []
    for name in ORDER:
        path = DIR / name
        if not path.exists():
            raise SystemExit(f"Missing file: {path}")
        files.append(path)

    merged = build_merged_md(files)
    OUT_MD.write_text(merged, encoding="utf-8")

    body = md_to_html(merged)
    # Fix accidental CSS typo protection - none expected

    html = f"""<!DOCTYPE html>
<html lang="fa" dir="rtl">
<head>
<meta charset="utf-8">
<title>بانک ۳۰۰ سؤالی آمادگی آزمون صلاحیت حرفه‌ای کارشناس هوشبری</title>
<style>{CSS}</style>
</head>
<body>
  <section class="cover">
    <h1>بانک ۳۰۰ سؤالی</h1>
    <p class="sub">آمادگی آزمون صلاحیت حرفه‌ای کارشناس هوشبری</p>
    <div class="box">Miller · Nagelhout · Marino · AHA 2025</div>
    <p class="meta">
      ۶ بخش ۵۰ سؤالی · چهارگزینه‌ای · فارسی<br>
      راه هوایی · دارو · مانیتورینگ · فیزیولوژی · بی‌حسی منطقه‌ای · بیماران خاص · ICU و احیا
    </p>
    <p class="footer-note">بانک تألیفی/آموزشی است و جایگزین دفترچه رسمی آزمون نیست.<br>
    اجرای بالینی موارد وابسته به پروتکل، تابع پروتکل مرکز درمانی است.</p>
  </section>
  {body}
</body>
</html>
"""
    # fix any CSS typo if introduced
    html = html.replace("color: # Pan0;", "color: # Pan0;")  # no-op placeholder
    # Actually I had a typo: `# Pan0` should be `#203040` or similar
    html = html.replace("color: # Pan0;", "color: #203040;")

    OUT_HTML.write_text(html, encoding="utf-8")

    chrome = Path(r"C:\Program Files\Google\Chrome\Application\chrome.exe")
    if not chrome.exists():
        chrome = Path(r"C:\Program Files (x86)\Microsoft\Edge\Application\msedge.exe")

    # Chrome needs absolute file URL
    html_url = OUT_HTML.resolve().as_uri()
    cmd = [
        str(chrome),
        "--headless=new",
        "--disable-gpu",
        "--no-pdf-header-footer",
        f"--print-to-pdf={OUT_PDF}",
        html_url,
    ]
    print("Running:", " ".join(cmd))
    proc = subprocess.run(cmd, capture_output=True, text=True)
    print("stdout:", proc.stdout)
    print("stderr:", proc.stderr)
    print("returncode:", proc.returncode)
    if OUT_PDF.exists():
        print(f"PDF OK: {OUT_PDF} ({OUT_PDF.stat().st_size} bytes)")
    else:
        raise SystemExit("PDF was not created")


if __name__ == "__main__":
    main()

